class Solution:
    def sumOfPrimesInRange(self, n):
        r = int(str(n)[::-1])
        lo, hi = min(n, r), max(n, r)
        limit = max(hi, 2)
        sieve = [True] * (limit + 1)
        sieve[0] = False
        if limit >= 1:
            sieve[1] = False
        p = 2
        while p * p <= limit:
            if sieve[p]:
                for m in range(p * p, limit + 1, p):
                    sieve[m] = False
            p += 1
        return sum(x for x in range(max(lo, 2), hi + 1) if sieve[x])

