class Solution:
    def sumOfPrimesInRange(self, n):
        def is_prime(x):
            if x < 2:
                return False
            if x < 4:
                return True
            if x % 2 == 0:
                return False
            i = 3
            while i * i <= x:
                if x % i == 0:
                    return False
                i += 2
            return True
        r = int(str(n)[::-1])
        lo, hi = min(n, r), max(n, r)
        total = 0
        for x in range(max(lo, 2), hi + 1):
            if is_prime(x):
                total += x
        return total

