var sumOfPrimesInRange = function(n) {
    function isPrime(x) {
        if (x < 2) return false;
        if (x < 4) return true;
        if (x % 2 === 0) return false;
        for (let i = 3; i * i <= x; i += 2) {
            if (x % i === 0) return false;
        }
        return true;
    }
    const r = parseInt(String(n).split('').reverse().join(''), 10);
    const lo = Math.min(n, r), hi = Math.max(n, r);
    let total = 0;
    for (let x = Math.max(lo, 2); x <= hi; x++) {
        if (isPrime(x)) total += x;
    }
    return total;
};
